{
  "summary": "This paper proposes Text Structure Prediction (TSP), a novel inter-sentence pretraining task that models hierarchical and ordering relationships between sentences to improve language model pretraining. TSP defines six classes combining three hierarchical levels and two ordering directions, and is trained jointly with MLM to provide richer self-supervised signals. Experiments show TSP consistently outperforms classical inter-sentence tasks across model scales, especially at large scale, on SuperGLUE benchmarks.",
  "strengths": [
    {
      "point": "Novel inter-sentence pretraining task leveraging hierarchical and ordering text structure",
      "evidence": "TSP models relationships along hierarchy (neighboring sentences, same paragraph, same document) and ordering (normal, reversed), defining six classes for classification."
    },
    {
      "point": "Consistent performance gains across model scales, especially at large scale",
      "evidence": "TSP outperforms NSP, SOP, and SSO baselines at Small, Base, and Large scales on SuperGLUE, with largest improvements at Large scale."
    },
    {
      "point": "Simple, self-supervised task with negligible computational overhead and easy integration",
      "evidence": "TSP is trained jointly with MLM in a single forward pass and can be combined with other pretraining methods like ELECTRA."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison to recent or more advanced inter-sentence pretraining objectives",
      "evidence": "No discussion or evaluation against recent discourse-aware or paragraph-level pretraining methods that could provide stronger baselines."
    },
    {
      "point": "Insufficient justification and ablation for key design choices",
      "evidence": "No analysis on why six classes were chosen, impact of sentence embedding strategy (average pooling vs alternatives), or sensitivity to fixed 15% partial shuffling rate."
    },
    {
      "point": "Limited evaluation scope and missing analysis on language modeling metrics",
      "evidence": "Experiments restricted to English SuperGLUE tasks; no evaluation on generation, summarization, non-English or larger diverse corpora; no reporting of perplexity or LM quality."
    },
    {
      "point": "Reproducibility concerns due to missing preprocessing and hyperparameter details",
      "evidence": "No specification of sentence segmentation, paragraph boundary detection, classifier architecture, learning rates, batch sizes, or loss weighting."
    },
    {
      "point": "Ambiguities and missing clarifications in methodology and integration",
      "evidence": "Unclear definition of hierarchical levels (e.g., adjacency of neighboring sentences), and insufficient explanation of how TSP integrates with ELECTRA's discriminator/generator setup."
    },
    {
      "point": "Limited discussion of limitations and generalizability",
      "evidence": "No analysis on why smaller models may degrade on some tasks, no evaluation on other languages or domains, and no consideration of cross-paragraph or cross-document discourse beyond defined levels."
    },
    {
      "point": "Potential confounding factors in evaluation",
      "evidence": "Baselines may not be matched for training steps or compute budgets, making it unclear if gains are solely due to TSP."
    }
  ],
  "questions": [
    {
      "question": "How does TSP compare to more recent discourse-aware or paragraph-level pretraining objectives?",
      "motivation": "Understanding relative benefits would clarify the novelty and practical advantage of TSP."
    },
    {
      "question": "How sensitive is TSP performance to the choice of six classes, sentence embedding method, and partial shuffling rate?",
      "motivation": "Ablations could inform robustness and guide future improvements or adaptations."
    },
    {
      "question": "Does TSP improve general language modeling quality (e.g., perplexity) or mainly downstream classification tasks?",
      "motivation": "This would indicate whether TSP enhances fundamental language understanding or task-specific performance."
    },
    {
      "question": "Can TSP generalize to other languages, domains, and larger or more diverse corpora?",
      "motivation": "Demonstrating broad applicability is important for practical adoption."
    },
    {
      "question": "What are the detailed preprocessing steps and hyperparameters to enable reproducibility?",
      "motivation": "Critical for verifying results and building upon this work."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
